256→/**
257→ * Parse a blend URL param like "rank_us_news_national:40,rank_forbes:30" into a record.
258→ */
259→export function parseBlendParam(raw: string | null): Record<string, number> {
260→  if (!raw) return {}
261→  const result: Record<string, number> = {}
262→  for (const pair of raw.split(',')) {
263→    const [field, weightStr] = pair.split(':')
264→    if (field && weightStr) {
265→      const weight = Number(weightStr)
266→      if (!isNaN(weight) && weight > 0) {
267→        result[field] = weight
268→      }
269→    }
270→  }
271→  return result
272→}
273→
274→/**
275→ * Serialize blend weights to a URL param string.
276→ * Only includes non-zero weights.
277→ */
278→export function serializeBlendWeights(weights: Record<string, number>): string {
279→  return Object.entries(weights)
280→    .filter(([, w]) => w > 0)
281→    .map(([field, weight]) => `${field}:${weight}`)
282→    .join(',')
283→}
284→
285→export function formatCellValue(value: unknown, unit?: SearchFieldUnit | null): string {
286→  if (value === null || value === undefined || value === '') return '—'
287→  const num = Number(value)
288→  if (unit === 'DOLLARS' && !isNaN(num)) {
289→    return `$${Math.round(num).toLocaleString()}`
290→  }
291→  if (unit === 'PERCENTAGE' && !isNaN(num)) {
292→    return `${(num * 100).toFixed(1)}%`
293→  }
294→  if (unit === 'MILES' && !isNaN(num)) {
295→    return `${num.toLocaleString()} mi`
296→  }
297→  return String(value)
298→}
