import { useState, useEffect, useRef, useCallback } from 'react'
import { Info } from 'lucide-react'
import { Tooltip, ActionIcon, Slider } from '@mantine/core'
import { useDebouncedCallback } from '@mantine/hooks'
import { Input } from '@/components/ui/input'
import type { SearchField, SearchFieldOption, SearchFieldUnit } from './types'
import { DataSourceTooltip } from './DataSourceTooltip'
import type { DataSource } from './useDataSources'
import { usePreferencesStore } from '@/stores/preferencesStore'

export const INLINE_CHECKBOX_THRESHOLD = 6

function FieldLabel({
  label,
  description,
  source,
}: {
  label: string
  description: string
  source?: DataSource
}) {
  return (
    <span style={{ display: 'inline-flex', alignItems: 'center', gap: 4 }}>
      {label}
      {description && (
        <Tooltip label={description} withArrow multiline maw={300}>
          <ActionIcon
            variant="subtle"
            color="gray"
            size="xs"
            aria-label={`Info about ${label}`}
          >
            <Info size={14} />
          </ActionIcon>
        </Tooltip>
      )}
      <DataSourceTooltip source={source} />
    </span>
  )
}

interface MultiSelectCheckboxesProps {
  field: SearchField
  options: SearchFieldOption[]
  maxSel: number | null
  value: unknown
  onChange: (value: unknown | undefined) => void
  source?: DataSource
}

export function MultiSelectCheckboxes({
  field,
  options,
  maxSel,
  value,
  onChange,
  source,
}: MultiSelectCheckboxesProps) {
  const [filterText, setFilterText] = useState('')

  const selectedValues: string[] =
    typeof value === 'object' && value !== null && 'values' in value
      ? (value as { values: string[] }).values
      : []
  const limitReached = maxSel !== null && selectedValues.length >= maxSel

  const useScalableUI = options.length >= INLINE_CHECKBOX_THRESHOLD

  const filteredOptions =
    useScalableUI && filterText.length > 0
      ? options.filter((opt) => opt.displayName.toLowerCase().includes(filterText.toLowerCase()))
      : options

  function handleToggle(optValue: string, checked: boolean) {
    const newValues = checked
      ? [...selectedValues, optValue]
      : selectedValues.filter((v) => v !== optValue)
    onChange(newValues.length > 0 ? { values: newValues } : undefined)
  }

  return (
    <div style={{ marginBottom: 16 }}>
      <fieldset style={{ border: 'none', margin: 0, padding: 0 }}>
        <legend
          style={{
            display: 'block',
            marginBottom: 4,
            fontSize: 14,
            fontWeight: 500,
            color: 'var(--mantine-color-gray-7)',
          }}
        >
          <FieldLabel label={field.label} description={field.description} source={source} />
        </legend>
        {useScalableUI && (
          <input
            type="text"
            style={{
              display: 'flex',
              height: 32,
              width: '100%',
              borderRadius: 6,
              border: '1px solid var(--mantine-color-gray-3)',
              backgroundColor: 'white',
              padding: '0 8px',
              fontSize: 14,
              marginBottom: 4,
              outline: 'none',
            }}
            placeholder={`Filter ${field.label.toLowerCase()}…`}
            value={filterText}
            onChange={(e) => setFilterText(e.target.value)}
            aria-label={`Filter ${field.label} options`}
          />
        )}
        <div
          style={{
            display: 'flex',
            flexDirection: 'column',
            gap: 4,
            ...(useScalableUI ? { maxHeight: 192, overflowY: 'auto' as const } : {}),
          }}
        >
          {filteredOptions.map((opt) => {
            const isChecked = selectedValues.includes(opt.value)
            const isDisabled = !isChecked && limitReached
            return (
              <label
                key={opt.value}
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  gap: 8,
                  cursor: isDisabled ? 'not-allowed' : 'pointer',
                  opacity: isDisabled ? 0.5 : 1,
                }}
              >
                <input
                  type="checkbox"
                  style={{
                    width: 16,
                    height: 16,
                    borderRadius: 4,
                    accentColor: 'var(--color-primary)',
                  }}
                  checked={isChecked}
                  disabled={isDisabled}
                  onChange={(e) => handleToggle(opt.value, e.target.checked)}
                />
                <span style={{ fontSize: 14, color: 'var(--mantine-color-gray-7)' }}>
                  {opt.displayName}
                </span>
              </label>
            )
          })}
          {useScalableUI && filterText.length > 0 && filteredOptions.length === 0 && (
            <p
              style={{
                padding: '4px 0',
                fontSize: 12,
                fontStyle: 'italic',
                color: 'var(--mantine-color-gray-5)',
              }}
            >
              No matching options
            </p>
          )}
        </div>
      </fieldset>
    </div>
  )
}

interface DebouncedTextInputProps {
  value: string
  onChange: (value: string) => void
  placeholder: string
  label: React.ReactNode
}

function DebouncedTextInput({ value, onChange, placeholder, label }: DebouncedTextInputProps) {
  const [localValue, setLocalValue] = useState(value)
  const isLocalChange = useRef(false)

  const debouncedOnChange = useDebouncedCallback((v: string) => {
    isLocalChange.current = false
    onChange(v)
  }, 400)

  useEffect(() => {
    if (!isLocalChange.current) {
      setLocalValue(value)
    }
  }, [value])

  return (
    <Input
      type="text"
      placeholder={placeholder}
      value={localValue}
      onChange={(e) => {
        const v = e.target.value
        isLocalChange.current = true
        setLocalValue(v)
        debouncedOnChange(v)
      }}
      aria-label={typeof label === 'string' ? label : undefined}
    />
  )
}

function getUnitLabel(unit: SearchFieldUnit | null | undefined): string | null {
  if (unit === 'DOLLARS') return '$'
  if (unit === 'PERCENTAGE') return '%'
  if (unit === 'MILES') return 'mi'
  return null
}

const numberInputStyle: React.CSSProperties = {
  display: 'flex',
  height: 32,
  width: '100%',
  borderRadius: 6,
  border: '1px solid var(--mantine-color-gray-3)',
  backgroundColor: 'white',
  padding: '0 8px',
  fontSize: 14,
  outline: 'none',
}

const clearButtonStyle: React.CSSProperties = {
  background: 'none',
  border: 'none',
  cursor: 'pointer',
  padding: '0 4px',
  fontSize: 14,
  color: 'var(--mantine-color-gray-5)',
  lineHeight: 1,
}

interface DebouncedNumberInputProps {
  value: string
  onChange: (value: string) => void
  placeholder: string
  ariaLabel: string
  min?: number
  max?: number
  step?: number
}

function DebouncedNumberInput({
  value,
  onChange,
  placeholder,
  ariaLabel,
  min,
  max,
  step,
}: DebouncedNumberInputProps) {
  const [localValue, setLocalValue] = useState(value)
  const isLocalChange = useRef(false)

  const debouncedOnChange = useDebouncedCallback((v: string) => {
    isLocalChange.current = false
    onChange(v)
  }, 400)

  useEffect(() => {
    if (!isLocalChange.current) {
      setLocalValue(value)
    }
  }, [value])

  return (
    <input
      type="number"
      style={numberInputStyle}
      placeholder={placeholder}
      value={localValue}
      min={min}
      max={max}
      step={step}
      aria-label={ariaLabel}
      onChange={(e) => {
        const v = e.target.value
        isLocalChange.current = true
        setLocalValue(v)
        debouncedOnChange(v)
      }}
    />
  )
}

interface FilterControlProps {
  field: SearchField
  value: unknown
  onChange: (value: unknown | undefined) => void
  dataSources?: Map<string, DataSource>
}

const labelStyle: React.CSSProperties = {
  display: 'block',
  marginBottom: 4,
  fontSize: 14,
  fontWeight: 500,
  color: 'var(--mantine-color-gray-7)',
}

const wrapperStyle: React.CSSProperties = { marginBottom: 16 }

export function FilterControl({ field, value, onChange, dataSources }: FilterControlProps) {
  const source = field.dataSourceID ? dataSources?.get(field.dataSourceID) : undefined
  if (field.searchability !== 'SEARCHABLE') {
    return (
      <div style={wrapperStyle}>
        <span style={labelStyle}>
          <FieldLabel label={field.label} description={field.description} source={source} />
        </span>
        <span style={{ fontSize: 12, fontStyle: 'italic', color: 'var(--mantine-color-gray-5)' }}>
          Display only
        </span>
      </div>
    )
  }

  if (field.__typename === 'TextSearchField') {
    const textValue =
      typeof value === 'object' && value !== null && 'query' in value
        ? String((value as { query: string }).query)
        : ''
    return (
      <div style={wrapperStyle}>
        <div style={{ display: 'block' }}>
          <span style={labelStyle}>
            <FieldLabel label={field.label} description={field.description} source={source} />
          </span>
          <DebouncedTextInput
            value={textValue}
            placeholder={field.label}
            label={field.label}
            onChange={(v) => onChange(v.length > 0 ? { query: v } : undefined)}
          />
        </div>
      </div>
    )
  }

  if (field.__typename === 'BinarySearchField') {
    const isChecked =
      typeof value === 'object' && value !== null && 'value' in value
        ? (value as { value: string }).value === '1'
        : false
    return (
      <div style={wrapperStyle}>
        <label style={{ display: 'flex', alignItems: 'center', gap: 8, cursor: 'pointer' }}>
          <input
            type="checkbox"
            style={{
              width: 16,
              height: 16,
              borderRadius: 4,
              accentColor: 'var(--color-primary)',
            }}
            checked={isChecked}
            onChange={(e) => onChange(e.target.checked ? { value: '1' } : undefined)}
          />
          <span style={{ fontSize: 14, fontWeight: 500, color: 'var(--mantine-color-gray-7)' }}>
            <FieldLabel label={field.label} description={field.description} source={source} />
          </span>
        </label>
      </div>
    )
  }

  if (field.__typename === 'ChoiceSearchField') {
    const options = field.options ?? []
    const maxSel = field.maxSelections ?? null

    if (maxSel === 1) {
      const selectedValue =
        typeof value === 'object' && value !== null && 'value' in value
          ? String((value as { value: string }).value)
          : ''
      return (
        <div style={wrapperStyle}>
          <label style={{ display: 'block' }}>
            <span style={labelStyle}>
              <FieldLabel label={field.label} description={field.description} source={source} />
            </span>
            <select
              style={{
                display: 'flex',
                height: 40,
                width: '100%',
                borderRadius: 6,
                border: '1px solid var(--mantine-color-gray-3)',
                backgroundColor: 'white',
                padding: '4px 12px',
                fontSize: 14,
              }}
              value={selectedValue}
              onChange={(e) => {
                const v = e.target.value
                onChange(v.length > 0 ? { value: v } : undefined)
              }}
            >
              <option value="">Any</option>
              {options.map((opt) => (
                <option key={opt.value} value={opt.value}>
                  {opt.displayName}
                </option>
              ))}
            </select>
          </label>
        </div>
      )
    }

    return (
      <MultiSelectCheckboxes
        field={field}
        options={options}
        maxSel={maxSel}
        value={value}
        onChange={onChange}
        source={source}
      />
    )
  }

  if (field.__typename === 'NumericalSearchField') {
    const isPercent = field.unit === 'PERCENTAGE'
    const unitLabel = getUnitLabel(field.unit)
    const rawValue =
      typeof value === 'object' && value !== null && 'value' in value
        ? (value as { value: number }).value
        : undefined
    const displayValue =
      rawValue !== undefined ? String(isPercent ? rawValue * 100 : rawValue) : ''

    const displayMin = field.min != null ? (isPercent ? field.min * 100 : field.min) : undefined
    const displayMax = field.max != null ? (isPercent ? field.max * 100 : field.max) : undefined
    const displayStep = field.step != null ? (isPercent ? field.step * 100 : field.step) : undefined

    return (
      <div style={wrapperStyle}>
        <span style={labelStyle}>
          <FieldLabel label={field.label} description={field.description} source={source} />
        </span>
        <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
          {unitLabel === '$' && (
            <span style={{ fontSize: 14, color: 'var(--mantine-color-gray-6)' }}>{unitLabel}</span>
          )}
          <DebouncedNumberInput
            value={displayValue}
            placeholder={field.label}
            ariaLabel={field.label}
            min={displayMin}
            max={displayMax}
            step={displayStep}
            onChange={(v) => {
              if (v === '') {
                onChange(undefined)
              } else {
                const num = Number(v)
                if (!isNaN(num)) {
                  onChange({ value: isPercent ? num / 100 : num })
                }
              }
            }}
          />
          {unitLabel && unitLabel !== '$' && (
            <span style={{ fontSize: 14, color: 'var(--mantine-color-gray-6)' }}>{unitLabel}</span>
          )}
          {rawValue !== undefined && (
            <button
              type="button"
              style={clearButtonStyle}
              onClick={() => onChange(undefined)}
              aria-label={`Clear ${field.label}`}
            >
              ×
            </button>
          )}
        </div>
      </div>
    )
  }

  if (field.__typename === 'NumericalRangeSearchField') {
    const isPercent = field.unit === 'PERCENTAGE'
    const unitLabel = getUnitLabel(field.unit)
    const rangeValue =
      typeof value === 'object' && value !== null ? (value as { min?: number; max?: number }) : {}
    const rawMin = rangeValue.min
    const rawMax = rangeValue.max
    const displayMin = rawMin !== undefined ? String(isPercent ? rawMin * 100 : rawMin) : ''
    const displayMax = rawMax !== undefined ? String(isPercent ? rawMax * 100 : rawMax) : ''

    const inputMin = field.min != null ? (isPercent ? field.min * 100 : field.min) : undefined
    const inputMax = field.max != null ? (isPercent ? field.max * 100 : field.max) : undefined
    const inputStep = field.step != null ? (isPercent ? field.step * 100 : field.step) : undefined

    const hasValue = rawMin !== undefined || rawMax !== undefined

    function handleRangeChange(which: 'min' | 'max', v: string) {
      const otherMin = which === 'min' ? undefined : rawMin
      const otherMax = which === 'max' ? undefined : rawMax
      if (v === '') {
        if (otherMin === undefined && otherMax === undefined) {
          onChange(undefined)
        } else {
          const next: { min?: number; max?: number } = {}
          if (otherMin !== undefined) next.min = otherMin
          if (otherMax !== undefined) next.max = otherMax
          onChange(next)
        }
      } else {
        const num = Number(v)
        if (!isNaN(num)) {
          const apiVal = isPercent ? num / 100 : num
          const next: { min?: number; max?: number } = {}
          if (which === 'min') {
            next.min = apiVal
            if (otherMax !== undefined) next.max = otherMax
          } else {
            if (otherMin !== undefined) next.min = otherMin
            next.max = apiVal
          }
          onChange(next)
        }
      }
    }

    return (
      <div style={wrapperStyle}>
        <span style={labelStyle}>
          <FieldLabel label={field.label} description={field.description} source={source} />
        </span>
        <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
          {unitLabel === '$' && (
            <span style={{ fontSize: 14, color: 'var(--mantine-color-gray-6)' }}>{unitLabel}</span>
          )}
          <DebouncedNumberInput
            value={displayMin}
            placeholder="Min"
            ariaLabel={`${field.label} min`}
            min={inputMin}
            max={inputMax}
            step={inputStep}
            onChange={(v) => handleRangeChange('min', v)}
          />
          <span style={{ fontSize: 14, color: 'var(--mantine-color-gray-6)' }}>–</span>
          <DebouncedNumberInput
            value={displayMax}
            placeholder="Max"
            ariaLabel={`${field.label} max`}
            min={inputMin}
            max={inputMax}
            step={inputStep}
            onChange={(v) => handleRangeChange('max', v)}
          />
          {unitLabel && unitLabel !== '$' && (
            <span style={{ fontSize: 14, color: 'var(--mantine-color-gray-6)' }}>{unitLabel}</span>
          )}
          {hasValue && (
            <button
              type="button"
              style={clearButtonStyle}
              onClick={() => onChange(undefined)}
              aria-label={`Clear ${field.label}`}
            >
              ×
            </button>
          )}
        </div>
      </div>
    )
  }

  if (field.__typename === 'GeoSearchField') {
    return (
      <GeoFilterControl field={field} value={value} onChange={onChange} source={source} />
    )
  }

  // Unsupported field types
  return (
    <div style={wrapperStyle}>
      <span style={labelStyle}>
        <FieldLabel label={field.label} description={field.description} source={source} />
      </span>
      <span style={{ fontSize: 12, fontStyle: 'italic', color: 'var(--mantine-color-gray-5)' }}>
        Coming soon
      </span>
    </div>
  )
}

// ── GeoFilterControl ────────────────────────────────────────────────────────

interface GeoFilterValue {
  latitude: number
  longitude: number
  radiusMiles: number
}

const DEFAULT_RADIUS_MILES = 50
const MIN_RADIUS_MILES = 10

function parseGeoValue(value: unknown): GeoFilterValue | undefined {
  if (
    typeof value === 'object' &&
    value !== null &&
    'latitude' in value &&
    'longitude' in value &&
    'radiusMiles' in value
  ) {
    return value as GeoFilterValue
  }
  return undefined
}

function GeoFilterControl({
  field,
  value,
  onChange,
  source,
}: {
  field: SearchField
  value: unknown
  onChange: (value: unknown | undefined) => void
  source?: DataSource
}) {
  const parsed = parseGeoValue(value)
  const maxRadius = field.maxRadiusMiles ?? 100
  const homeLatitude = usePreferencesStore((s) => s.homeLatitude)
  const homeLongitude = usePreferencesStore((s) => s.homeLongitude)

  const [localLat, setLocalLat] = useState(
    parsed?.latitude !== undefined
      ? String(parsed.latitude)
      : field.defaultLatitude != null
        ? String(field.defaultLatitude)
        : homeLatitude != null
          ? String(homeLatitude)
          : '',
  )
  const [localLng, setLocalLng] = useState(
    parsed?.longitude !== undefined
      ? String(parsed.longitude)
      : field.defaultLongitude != null
        ? String(field.defaultLongitude)
        : homeLongitude != null
          ? String(homeLongitude)
          : '',
  )
  const [localRadius, setLocalRadius] = useState(
    parsed?.radiusMiles ?? DEFAULT_RADIUS_MILES,
  )

  const isLocalChange = useRef(false)

  // Sync from external value changes (e.g. URL navigation)
  useEffect(() => {
    if (!isLocalChange.current) {
      if (parsed) {
        setLocalLat(String(parsed.latitude))
        setLocalLng(String(parsed.longitude))
        setLocalRadius(parsed.radiusMiles)
      } else {
        setLocalLat(
          field.defaultLatitude != null
            ? String(field.defaultLatitude)
            : homeLatitude != null
              ? String(homeLatitude)
              : '',
        )
        setLocalLng(
          field.defaultLongitude != null
            ? String(field.defaultLongitude)
            : homeLongitude != null
              ? String(homeLongitude)
              : '',
        )
        setLocalRadius(DEFAULT_RADIUS_MILES)
      }
    }
  }, [value, field.defaultLatitude, field.defaultLongitude, homeLatitude, homeLongitude]) // eslint-disable-line react-hooks/exhaustive-deps

  const emitChange = useCallback(
    (lat: string, lng: string, radius: number) => {
      isLocalChange.current = false
      const latNum = Number(lat)
      const lngNum = Number(lng)
      if (lat === '' && lng === '') {
        onChange(undefined)
      } else if (!isNaN(latNum) && !isNaN(lngNum) && lat !== '' && lng !== '') {
        onChange({ latitude: latNum, longitude: lngNum, radiusMiles: radius })
      }
    },
    [onChange],
  )

  const debouncedEmit = useDebouncedCallback(
    (lat: string, lng: string, radius: number) => emitChange(lat, lng, radius),
    400,
  )

  const hasValue = parsed !== undefined

  return (
    <div style={wrapperStyle}>
      <span style={labelStyle}>
        <FieldLabel label={field.label} description={field.description} source={source} />
      </span>
      <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
          <DebouncedNumberInput
            value={localLat}
            placeholder="Latitude"
            ariaLabel={`${field.label} latitude`}
            min={-90}
            max={90}
            step={0.01}
            onChange={(v) => {
              isLocalChange.current = true
              setLocalLat(v)
              debouncedEmit(v, localLng, localRadius)
            }}
          />
          <DebouncedNumberInput
            value={localLng}
            placeholder="Longitude"
            ariaLabel={`${field.label} longitude`}
            min={-180}
            max={180}
            step={0.01}
            onChange={(v) => {
              isLocalChange.current = true
              setLocalLng(v)
              debouncedEmit(localLat, v, localRadius)
            }}
          />
          {hasValue && (
            <button
              type="button"
              style={clearButtonStyle}
              onClick={() => {
                isLocalChange.current = true
                setLocalLat(
                  field.defaultLatitude != null ? String(field.defaultLatitude) : '',
                )
                setLocalLng(
                  field.defaultLongitude != null ? String(field.defaultLongitude) : '',
                )
                setLocalRadius(DEFAULT_RADIUS_MILES)
                onChange(undefined)
              }}
              aria-label={`Clear ${field.label}`}
            >
              ×
            </button>
          )}
        </div>
        <div>
          <span style={{ fontSize: 12, color: 'var(--mantine-color-gray-6)', marginBottom: 2, display: 'block' }}>
            Radius: {localRadius} mi
          </span>
          <Slider
            value={localRadius}
            min={MIN_RADIUS_MILES}
            max={maxRadius}
            step={10}
            label={(v) => `${v} mi`}
            aria-label={`${field.label} radius`}
            onChange={(v) => {
              isLocalChange.current = true
              setLocalRadius(v)
            }}
            onChangeEnd={(v) => {
              emitChange(localLat, localLng, v)
            }}
          />
        </div>
      </div>
    </div>
  )
}

import { useState } from 'react'
import { Link, useNavigate } from 'react-router-dom'
import {
  Container,
  Title,
  Text,
  TextInput,
  NativeSelect,
  SimpleGrid,
  Group,
  Stack,
  Card,
  Box,
} from '@mantine/core'
import { Search, BarChart3, Filter, Bookmark } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { US_STATES, SampleSearchCarousel } from '@/components/search'

const RANKING_OPTIONS = [
  { value: '', label: 'Any rank' },
  { value: '25', label: 'Top 25' },
  { value: '50', label: 'Top 50' },
  { value: '100', label: 'Top 100' },
  { value: '200', label: 'Top 200' },
]

const features = [
  {
    icon: BarChart3,
    title: 'Comprehensive Data',
    description:
      'Access detailed information on thousands of colleges — from acceptance rates and SAT scores to net price and graduation outcomes.',
  },
  {
    icon: Filter,
    title: 'Faceted Search',
    description:
      'Narrow your list by dozens of criteria at once. Combine filters across academics, cost, location, size, and campus culture.',
  },
  {
    icon: Bookmark,
    title: 'Save & Compare',
    description:
      'Build your personal college list, save searches, and compare schools side by side to make confident decisions.',
  },
]

export function Home() {
  const [name, setName] = useState('')
  const [state, setState] = useState('')
  const [rankMax, setRankMax] = useState('')
  const [major, setMajor] = useState('')
  const navigate = useNavigate()

  function buildSearchParams(): URLSearchParams {
    const params = new URLSearchParams()
    if (name.trim()) params.set('q', name.trim())
    if (state) params.set('state', state)
    if (rankMax) params.set('rank_us_news_national', rankMax)
    if (major.trim()) params.set('fields_of_study', major.trim())
    return params
  }

  function handleSearch(e: React.FormEvent) {
    e.preventDefault()
    const params = buildSearchParams()
    const qs = params.toString()
    navigate(qs ? `/search?${qs}` : '/search')
  }

  const moreFiltersParams = buildSearchParams()
  const moreFiltersHref = moreFiltersParams.toString()
    ? `/search?${moreFiltersParams.toString()}`
    : '/search'

  return (
    <main style={{ display: 'flex', flex: 1, flexDirection: 'column' }}>
      {/* ── Hero ──────────────────────────────────────────────────────── */}
      <Box component="section" bg="gray.0" py={{ base: 40, sm: 60, md: 80 }} px="md">
        <Container size="sm" style={{ textAlign: 'center' }}>
          <Title order={1} mb="sm" c="brand.9" fz={{ base: 36, sm: 48, lg: 60 }}>
            College Power Search
          </Title>
          <Text size="lg" c="dimmed" mb="xl">
            Find your perfect college — by academics, cost, location, athletics, and more.
          </Text>

          <form onSubmit={handleSearch}>
            <Stack gap="md">
              {/* Name search */}
              <TextInput
                type="search"
                placeholder="College name…"
                value={name}
                onChange={(e) => setName(e.target.value)}
                leftSection={<Search size={16} />}
                size="lg"
              />

              {/* Facet row */}
              <SimpleGrid cols={{ base: 1, sm: 3 }} spacing="sm">
                <NativeSelect
                  label="State"
                  value={state}
                  onChange={(e) => setState(e.target.value)}
                  data={[
                    { value: '', label: 'Any state' },
                    ...US_STATES.map((s) => ({ value: s.value, label: s.label })),
                  ]}
                />
                <NativeSelect
                  label="Ranking"
                  value={rankMax}
                  onChange={(e) => setRankMax(e.target.value)}
                  data={RANKING_OPTIONS}
                />
                <TextInput
                  label="Major"
                  placeholder="e.g. Biology"
                  value={major}
                  onChange={(e) => setMajor(e.target.value)}
                />
              </SimpleGrid>

              {/* Actions */}
              <Group justify="space-between">
                <Link
                  to={moreFiltersHref}
                  style={{
                    fontSize: '0.875rem',
                    fontWeight: 500,
                    color: 'var(--color-accent)',
                    textDecoration: 'none',
                  }}
                >
                  More filters &rsaquo;
                </Link>
                <Button type="submit" size="lg" variant="accent">
                  Search
                </Button>
              </Group>
            </Stack>
          </form>
        </Container>
      </Box>

      {/* ── Sample searches ─────────────────────────────────────────────── */}
      <SampleSearchCarousel />

      {/* ── Why CPS? ───────────────────────────────────────────────────── */}
      <Box component="section" bg="gray.0" py="xl" px="md">
        <Container size="lg">
          <Title order={2} ta="center" mb="xl" c="brand.9">
            Why College Power Search?
          </Title>

          <SimpleGrid cols={{ base: 1, sm: 3 }} spacing="lg">
            {features.map(({ icon: Icon, title, description }) => (
              <Card key={title} shadow="sm" withBorder>
                <Box
                  mb="sm"
                  style={{
                    display: 'inline-flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    width: 44,
                    height: 44,
                    borderRadius: 8,
                    backgroundColor: 'var(--color-primary)',
                  }}
                >
                  <Icon size={20} color="#fff" />
                </Box>
                <Text fw={600} size="lg" c="brand.9" mb="xs">
                  {title}
                </Text>
                <Text size="sm" c="dimmed" lh={1.625}>
                  {description}
                </Text>
              </Card>
            ))}
          </SimpleGrid>
        </Container>
      </Box>
    </main>
  )
}

