func (r *queryResolver) CipCodes(ctx context.Context, search string, limit *int) ([]*model.CipCode, error) {
	if len(search) < 2 {
		return []*model.CipCode{}, nil
	}

	n := 20
	if limit != nil {
		n = *limit
	}
	if n > 50 {
		n = 50
	}
	if n < 1 {
		n = 1
	}

	const q = `
		SELECT DISTINCT code, description
		FROM search_base.cip_data
		WHERE level = 'BACHELOR'
		  AND (description ILIKE '%' || $1 || '%' OR code ILIKE '%' || $1 || '%')
		ORDER BY description
		LIMIT $2`

	rows, err := r.DB.Query(ctx, q, search, n)
	if err != nil {
		return nil, fmt.Errorf("resolver: cipCodes query: %w", err)
	}
	defer rows.Close()

	var out []*model.CipCode
	for rows.Next() {
		var c model.CipCode
		if err := rows.Scan(&c.Code, &c.Description); err != nil {
			return nil, fmt.Errorf("resolver: cipCodes scan: %w", err)
		}
		out = append(out, &c)
	}
	if err := rows.Err(); err != nil {
		return nil, fmt.Errorf("resolver: cipCodes rows: %w", err)
	}
	return out, nil
}

