import { useState, useEffect, useRef, useCallback } from 'react'
import { Info } from 'lucide-react'
import { Tooltip, ActionIcon } from '@mantine/core'
import { useDebouncedCallback } from '@mantine/hooks'
import { graphql } from 'gql.tada'
import { useQuery } from '@/lib/graphql'
import { DataSourceTooltip } from './DataSourceTooltip'
import type { SearchField } from './types'
import type { DataSource } from './useDataSources'

const CipCodesQuery = graphql(`
  query CipCodes($search: String!, $limit: Int) {
    cipCodes(search: $search, limit: $limit) {
      code
      description
    }
  }
`)

const CipCodesByCodeQuery = graphql(`
  query CipCodesByCode($codes: [String!]!) {
    cipCodesByCode(codes: $codes) {
      code
      description
    }
  }
`)

interface CipCodeSelectProps {
  field: SearchField
  value: unknown
  onChange: (value: unknown | undefined) => void
  source?: DataSource
}

interface SelectedCip {
  code: string
  description: string
}

export function CipCodeSelect({ field, value, onChange, source }: CipCodeSelectProps) {
  const [searchText, setSearchText] = useState('')
  const [debouncedSearch, setDebouncedSearch] = useState('')
  const [selected, setSelected] = useState<SelectedCip[]>([])
  const initializedRef = useRef(false)

  // Extract current CIP codes from filter value
  const selectedCodes: string[] =
    typeof value === 'object' && value !== null && 'values' in value
      ? (value as { values: string[] }).values
      : []

  // Debounce the search text
  const debouncedSetSearch = useDebouncedCallback((v: string) => {
    setDebouncedSearch(v)
  }, 400)

  // Search query — paused until 2+ chars
  const [searchResult] = useQuery({
    query: CipCodesQuery,
    variables: { search: debouncedSearch, limit: 20 },
    pause: debouncedSearch.length < 2,
  })

  // Reverse lookup for URL-restored codes
  const needsLookup = selectedCodes.length > 0 && !initializedRef.current
  const [lookupResult] = useQuery({
    query: CipCodesByCodeQuery,
    variables: { codes: selectedCodes },
    pause: !needsLookup,
  })

  // Initialize selected items from URL-restored codes
  useEffect(() => {
    if (lookupResult.data && !initializedRef.current) {
      initializedRef.current = true
      const items = lookupResult.data.cipCodesByCode.map(
        (c: { code: string; description: string }) => ({
          code: c.code,
          description: c.description,
        }),
      )
      setSelected(items)
    }
  }, [lookupResult.data])

  // Mark initialized when no codes to look up
  useEffect(() => {
    if (selectedCodes.length === 0) {
      initializedRef.current = true
    }
  }, []) // eslint-disable-line react-hooks/exhaustive-deps

  // Sync selected state when value is cleared externally
  useEffect(() => {
    if (selectedCodes.length === 0 && selected.length > 0 && initializedRef.current) {
      setSelected([])
    }
  }, [selectedCodes.length]) // eslint-disable-line react-hooks/exhaustive-deps

  const handleToggle = useCallback(
    (code: string, description: string, checked: boolean) => {
      let newSelected: SelectedCip[]
      if (checked) {
        newSelected = [...selected, { code, description }]
      } else {
        newSelected = selected.filter((s) => s.code !== code)
      }
      setSelected(newSelected)
      const newCodes = newSelected.map((s) => s.code)
      onChange(newCodes.length > 0 ? { values: newCodes } : undefined)
    },
    [selected, onChange],
  )

  const handleRemove = useCallback(
    (code: string) => {
      const newSelected = selected.filter((s) => s.code !== code)
      setSelected(newSelected)
      const newCodes = newSelected.map((s) => s.code)
      onChange(newCodes.length > 0 ? { values: newCodes } : undefined)
    },
    [selected, onChange],
  )

  const searchResults =
    debouncedSearch.length >= 2 && searchResult.data
      ? searchResult.data.cipCodes
      : []

  const showResults = debouncedSearch.length >= 2

  return (
    <div style={{ marginBottom: 16 }}>
      <fieldset style={{ border: 'none', margin: 0, padding: 0 }}>
        <legend
          style={{
            display: 'block',
            marginBottom: 4,
            fontSize: 14,
            fontWeight: 500,
            color: 'var(--mantine-color-gray-7)',
          }}
        >
          <span style={{ display: 'inline-flex', alignItems: 'center', gap: 4 }}>
            {field.label}
            {field.description && (
              <Tooltip label={field.description} withArrow multiline maw={300}>
                <ActionIcon
                  variant="subtle"
                  color="gray"
                  size="xs"
                  aria-label={`Info about ${field.label}`}
                >
                  <Info size={14} />
                </ActionIcon>
              </Tooltip>
            )}
            <DataSourceTooltip source={source} />
          </span>
        </legend>

        {/* Selected items as removable tags */}
        {selected.length > 0 && (
          <div
            style={{
              display: 'flex',
              flexWrap: 'wrap',
              gap: 4,
              marginBottom: 6,
            }}
          >
            {selected.map((s) => (
              <span
                key={s.code}
                style={{
                  display: 'inline-flex',
                  alignItems: 'center',
                  gap: 4,
                  padding: '2px 8px',
                  fontSize: 12,
                  borderRadius: 4,
                  backgroundColor: 'var(--mantine-color-brand-0, #e8edf5)',
                  color: 'var(--mantine-color-gray-8)',
                  lineHeight: 1.5,
                }}
              >
                {s.description}
                <button
                  type="button"
                  onClick={() => handleRemove(s.code)}
                  aria-label={`Remove ${s.description}`}
                  style={{
                    background: 'none',
                    border: 'none',
                    cursor: 'pointer',
                    padding: 0,
                    fontSize: 14,
                    lineHeight: 1,
                    color: 'var(--mantine-color-gray-5)',
                  }}
                >
                  ×
                </button>
              </span>
            ))}
          </div>
        )}

        {/* Search input */}
        <input
          type="text"
          style={{
            display: 'flex',
            height: 32,
            width: '100%',
            borderRadius: 6,
            border: '1px solid var(--mantine-color-gray-3)',
            backgroundColor: 'white',
            padding: '0 8px',
            fontSize: 14,
            marginBottom: 4,
            outline: 'none',
          }}
          placeholder="Search fields of study…"
          value={searchText}
          onChange={(e) => {
            setSearchText(e.target.value)
            debouncedSetSearch(e.target.value)
          }}
          aria-label="Search fields of study"
        />

        {/* Results list */}
        {showResults && (
          <div
            style={{
              display: 'flex',
              flexDirection: 'column',
              gap: 4,
              maxHeight: 192,
              overflowY: 'auto',
            }}
          >
            {searchResult.fetching && (
              <p
                style={{
                  padding: '4px 0',
                  fontSize: 12,
                  fontStyle: 'italic',
                  color: 'var(--mantine-color-gray-5)',
                }}
              >
                Searching…
              </p>
            )}
            {!searchResult.fetching && searchResults.length === 0 && (
              <p
                style={{
                  padding: '4px 0',
                  fontSize: 12,
                  fontStyle: 'italic',
                  color: 'var(--mantine-color-gray-5)',
                }}
              >
                No matching fields of study
              </p>
            )}
            {searchResults.map((cip) => {
              const isChecked = selectedCodes.includes(cip.code)
              return (
                <label
                  key={cip.code}
                  style={{
                    display: 'flex',
                    alignItems: 'center',
                    gap: 8,
                    cursor: 'pointer',
                  }}
                >
                  <input
                    type="checkbox"
                    style={{
                      width: 16,
                      height: 16,
                      borderRadius: 4,
                      accentColor: 'var(--color-primary)',
                      flexShrink: 0,
                    }}
                    checked={isChecked}
                    onChange={(e) => handleToggle(cip.code, cip.description, e.target.checked)}
                  />
                  <span style={{ fontSize: 14, color: 'var(--mantine-color-gray-7)' }}>
                    {cip.description}
                  </span>
                </label>
              )
            })}
          </div>
        )}
      </fieldset>
    </div>
  )
}

