import { describe, it, expect, vi, beforeEach } from 'vitest'
import { screen } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { MemoryRouter } from 'react-router-dom'
import { renderWithMantine } from '@/test/render'
import { Home } from './Home'

vi.mock('urql', () => ({
  useQuery: () => [{ fetching: false, data: null }],
}))

vi.mock('@/stores/preferencesStore', () => ({
  usePreferencesStore: (selector: (s: Record<string, unknown>) => unknown) =>
    selector({ homeLatitude: null, homeLongitude: null, homeState: null, loaded: false, loading: false, load: vi.fn(), update: vi.fn(), clear: vi.fn() }),
}))

const mockNavigate = vi.fn()
vi.mock('react-router-dom', async () => {
  const actual = await vi.importActual('react-router-dom')
  return {
    ...actual,
    useNavigate: () => mockNavigate,
  }
})

function renderHome() {
  return renderWithMantine(
    <MemoryRouter>
      <Home />
    </MemoryRouter>,
  )
}

describe('Home', () => {
  beforeEach(() => {
    mockNavigate.mockReset()
  })

  it('renders the hero heading', () => {
    renderHome()
    expect(
      screen.getByRole('heading', { level: 1, name: /college power search/i }),
    ).toBeInTheDocument()
  })

  it('renders the search input', () => {
    renderHome()
    expect(screen.getByPlaceholderText(/college name/i)).toBeInTheDocument()
  })

  it('renders the search submit button', () => {
    renderHome()
    expect(screen.getByRole('button', { name: /search/i })).toBeInTheDocument()
  })

  it('renders all feature cards', () => {
    renderHome()
    expect(screen.getByText('Comprehensive Data')).toBeInTheDocument()
    expect(screen.getByText('Faceted Search')).toBeInTheDocument()
    expect(screen.getByText('Save & Compare')).toBeInTheDocument()
  })

  it('updates search input value as user types', async () => {
    const user = userEvent.setup()
    renderHome()
    const input = screen.getByPlaceholderText(/college name/i)
    await user.type(input, 'MIT')
    expect(input).toHaveValue('MIT')
  })

  // ── New facet controls ───────────────────────────────────────────────────

  it('renders state dropdown with "Any state" default', () => {
    renderHome()
    const select = screen.getByRole('combobox', { name: /state/i })
    expect(select).toBeInTheDocument()
    expect(select).toHaveValue('')
    expect(screen.getByText('Any state')).toBeInTheDocument()
  })

  it('renders ranking dropdown with "Any rank" default', () => {
    renderHome()
    const select = screen.getByRole('combobox', { name: /ranking/i })
    expect(select).toBeInTheDocument()
    expect(select).toHaveValue('')
    expect(screen.getByText('Any rank')).toBeInTheDocument()
  })

  it('renders major text input', () => {
    renderHome()
    expect(screen.getByPlaceholderText(/e\.g\. biology/i)).toBeInTheDocument()
  })

  it('renders "More filters" link', () => {
    renderHome()
    const link = screen.getByText(/more filters/i)
    expect(link).toBeInTheDocument()
    expect(link.closest('a')).toHaveAttribute('href', '/search')
  })

  it('navigates to /search with name param on submit', async () => {
    const user = userEvent.setup()
    renderHome()
    await user.type(screen.getByPlaceholderText(/college name/i), 'MIT')
    await user.click(screen.getByRole('button', { name: /search/i }))
    expect(mockNavigate).toHaveBeenCalledWith('/search?q=MIT')
  })

  it('navigates with state param when state is selected', async () => {
    const user = userEvent.setup()
    renderHome()
    await user.selectOptions(screen.getByRole('combobox', { name: /state/i }), 'CA')
    await user.click(screen.getByRole('button', { name: /search/i }))
    expect(mockNavigate).toHaveBeenCalledWith('/search?state=CA')
  })

  it('navigates with ranking param when ranking is selected', async () => {
    const user = userEvent.setup()
    renderHome()
    await user.selectOptions(screen.getByRole('combobox', { name: /ranking/i }), '50')
    await user.click(screen.getByRole('button', { name: /search/i }))
    expect(mockNavigate).toHaveBeenCalledWith('/search?rank_us_news_national=50')
  })

  it('navigates with major param when major is entered', async () => {
    const user = userEvent.setup()
    renderHome()
    await user.type(screen.getByPlaceholderText(/e\.g\. biology/i), 'Biology')
    await user.click(screen.getByRole('button', { name: /search/i }))
    expect(mockNavigate).toHaveBeenCalledWith('/search?fields_of_study=Biology')
  })

  it('navigates with all params when all facets are filled', async () => {
    const user = userEvent.setup()
    renderHome()
    await user.type(screen.getByPlaceholderText(/college name/i), 'Stanford')
    await user.selectOptions(screen.getByRole('combobox', { name: /state/i }), 'CA')
    await user.selectOptions(screen.getByRole('combobox', { name: /ranking/i }), '25')
    await user.type(screen.getByPlaceholderText(/e\.g\. biology/i), 'CS')
    await user.click(screen.getByRole('button', { name: /search/i }))
    expect(mockNavigate).toHaveBeenCalledWith(
      '/search?q=Stanford&state=CA&rank_us_news_national=25&fields_of_study=CS',
    )
  })

  it('navigates to /search with no params when all fields empty', async () => {
    const user = userEvent.setup()
    renderHome()
    await user.click(screen.getByRole('button', { name: /search/i }))
    expect(mockNavigate).toHaveBeenCalledWith('/search')
  })

  it('renders the sample searches carousel heading', () => {
    renderHome()
    expect(
      screen.getByRole('heading', { level: 2, name: /explore sample searches/i }),
    ).toBeInTheDocument()
  })

  it('updates "More filters" link with current params', async () => {
    const user = userEvent.setup()
    renderHome()
    await user.selectOptions(screen.getByRole('combobox', { name: /state/i }), 'NY')
    const link = screen.getByText(/more filters/i).closest('a')
    expect(link).toHaveAttribute('href', '/search?state=NY')
  })
})

